// AUTO-GENERATED brand-mark path data — official single-path marks from Simple Icons (CC0 / public
// domain; used nominatively to identify integrations). One 24×24 <path> + the brand hex per provider.
// 78 of the registry's providers have a clean vector mark here; every OTHER provider renders a
// real brand favicon (proxied + edge-cached same-origin via /api/provider-icon, see provider-logo.tsx +
// PROVIDER_DOMAINS in provider-branding.ts), falling back to an a11y-safe monogram only on load error.
// Simple Icons has DROPPED many brands (Slack, Twilio, LinkedIn, OpenAI…) over trademark policy — those are
// covered by the favicon path, NOT here. To add a mark: copy the single <path d> + brand hex from the
// provider's Simple Icons entry (simpleicons.org). Coverage (a mark OR a favicon domain for every registry
// slug) is enforced by apps/web/src/lib/provider-logos.test.ts, so a bare-monogram provider fails CI.

export interface ProviderLogoPath {
  /** The 24×24 viewBox single-path mark. */
  readonly path: string;
  /** The brand colour baked into the mark (null ⇒ tint with the branding brandColor). */
  readonly hex: string | null;
}

